window.SRVPLUS = window.SRVPLUS || {}; SRVPLUS.questions = SRVPLUS.questions || [];
SRVPLUS.questions.push(
  { id:"D2-001", domain:2, obj:"2.1", diff:"easy", q:"A sysadmin must install an OS on a server with a single 6 TB boot disk that will hold six partitions. Which partition table should be selected?", options:["GPT, because it supports drives larger than 2 TB and more than four partitions","MBR, because it is the modern standard for large disks","FAT32, because it scales to any drive size","An extended partition only, because GPT is limited to four partitions"], answer:0, explain:"<strong>GPT, because it supports drives larger than 2 TB and more than four partitions</strong> is correct. GPT supports drives larger than 2 TB and far more than four partitions, and modern UEFI firmware uses it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>MBR, because it is the modern standard for large disks</b>: MBR is the older method and cannot address drives larger than 2 TB.</span><span class='qd'><b>FAT32, because it scales to any drive size</b>: FAT32 is a file system, not a partition table, and does not solve the 2 TB limit.</span><span class='qd'><b>An extended partition only, because GPT is limited to four partitions</b>: GPT is not limited to four partitions; that four-partition limit belongs to MBR.</span>" },
  { id:"D2-002", domain:2, obj:"2.1", diff:"medium", q:"An administrator needs to deploy 50 identical Windows servers quickly and consistently using a perfectly configured reference machine. Which method best fits?", options:["Manual DVD installation on each server individually","Imaging from a source computer to the destination servers","A live USB installation booted on each server","A virtual-to-physical (V2P) migration"], answer:1, explain:"<strong>Imaging from a source computer to the destination servers</strong> is correct. Imaging captures a configured source computer and deploys it to many destination servers identically and efficiently.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manual DVD installation on each server individually</b>: Manual DVD installs are slow and inconsistent across 50 machines.</span><span class='qd'><b>A live USB installation booted on each server</b>: Live USB boots the OS from the drive and is not a mass-deployment method.</span><span class='qd'><b>A virtual-to-physical (V2P) migration</b>: V2P migrates a single VM to physical hardware, not a 50-server rollout.</span>" },
  { id:"D2-003", domain:2, obj:"2.1", diff:"medium", q:"A Linux administrator wants an unattended installation that supplies all partition and package choices without prompting. Which file accomplishes this?", options:["An /etc/hosts file","A Kickstart answer file","A PowerShell answer file","A VMFS descriptor file"], answer:1, explain:"<strong>A Kickstart answer file</strong> is correct. Linux Kickstart files act as answer files providing every installation option so the installer never prompts the user.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An /etc/hosts file</b>: The /etc/hosts file maps hostnames to IP addresses; it is unrelated to installation.</span><span class='qd'><b>A PowerShell answer file</b>: PowerShell is a Windows shell and does not drive Linux Kickstart installations.</span><span class='qd'><b>A VMFS descriptor file</b>: VMFS is a VMware file system for VM images, not an installation answer file.</span>" },
  { id:"D2-004", domain:2, obj:"2.1", diff:"easy", q:"Which installation target places the OS directly on the server hardware with no hypervisor layer?", options:["Virtualized installation","Type 2 hypervisor guest","Cloud IaaS instance","Bare-metal installation"], answer:3, explain:"<strong>Bare-metal installation</strong> is correct. A bare-metal installation puts the OS directly on the physical hardware without sharing resources through a hypervisor.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Virtualized installation</b>: A virtualized installation runs inside a hypervisor-managed environment.</span><span class='qd'><b>Type 2 hypervisor guest</b>: A Type 2 hypervisor guest is by definition virtualized, not bare metal.</span><span class='qd'><b>Cloud IaaS instance</b>: A cloud IaaS instance is a VM hosted in a provider data center, not bare metal.</span>" },
  { id:"D2-005", domain:2, obj:"2.1", diff:"medium", q:"A business is moving an aging physical Windows server into its VMware environment without reinstalling the OS. Which migration is this?", options:["Virtual-to-physical (V2P)","Virtual-to-virtual (V2V)","Bare-metal restore","Physical-to-virtual (P2V)"], answer:3, explain:"<strong>Physical-to-virtual (P2V)</strong> is correct. A P2V migration converts an existing physical server into a VM, which is exactly this scenario.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Virtual-to-physical (V2P)</b>: V2P moves a VM onto physical hardware, the opposite direction.</span><span class='qd'><b>Virtual-to-virtual (V2V)</b>: V2V moves a VM between two virtualization platforms, but the source here is physical.</span><span class='qd'><b>Bare-metal restore</b>: A bare-metal restore recovers a backup to hardware, not a physical-to-VM conversion.</span>" },
  { id:"D2-006", domain:2, obj:"2.1", diff:"hard", q:"A Linux web server must host a static site with minimal administration and the lowest resource footprint. Which install choice best meets this?", options:["A full desktop GUI installation","A Type 2 hypervisor on the workstation","A command-line-only installation with no GUI","A dual-boot live USB configuration"], answer:2, explain:"<strong>A command-line-only installation with no GUI</strong> is correct. A command-line-only Linux install consumes the fewest resources and is well suited to a low-maintenance static web server.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A full desktop GUI installation</b>: A full GUI wastes resources the static server does not need.</span><span class='qd'><b>A Type 2 hypervisor on the workstation</b>: A Type 2 hypervisor is for desktop testing, not a production web server.</span><span class='qd'><b>A dual-boot live USB configuration</b>: A dual-boot live USB is a portable/repair scenario, not a production deployment.</span>" },
  { id:"D2-007", domain:2, obj:"2.1", diff:"medium", q:"Which Windows Server installation option provides a command-line-only OS with a smaller footprint and better performance than the full GUI?", options:["Windows PE","Server Manager","Hyper-V Manager","Server Core"], answer:3, explain:"<strong>Server Core</strong> is correct. Server Core is the command-line-only Windows Server installation with a reduced footprint and performance benefits.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Windows PE</b>: Windows PE is a lightweight preinstallation environment, not a server OS install mode.</span><span class='qd'><b>Server Manager</b>: Server Manager is a GUI management console, not an installation option.</span><span class='qd'><b>Hyper-V Manager</b>: Hyper-V Manager is a virtualization console, not an OS installation mode.</span>" },
  { id:"D2-008", domain:2, obj:"2.1", diff:"easy", q:"A self-service developer environment needs pre-built VM configurations that developers can deploy on demand. What should the admin create?", options:["Kickstart files for bare metal","A hosts file entry per developer","A V2P migration job","VM templates"], answer:3, explain:"<strong>VM templates</strong> is correct. VM templates are pre-generated configurations developers can deploy on demand without waiting on an administrator.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Kickstart files for bare metal</b>: Kickstart files automate bare-metal installs, not on-demand VM cloning.</span><span class='qd'><b>A hosts file entry per developer</b>: Hosts file entries handle name resolution, not VM provisioning.</span><span class='qd'><b>A V2P migration job</b>: V2P migrates VMs to hardware and does not provide self-service templates.</span>" },
  { id:"D2-009", domain:2, obj:"2.1", diff:"medium", q:"An administrator wants to add updated drivers, patches, and applications into a single automated Windows install. Microsoft calls this a what?", options:["Live installation","Bare-metal restore","Slipstream installation","V2V migration"], answer:2, explain:"<strong>Slipstream installation</strong> is correct. Microsoft refers to automated deployments that bundle patches, drivers, and applications as slipstream installations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Live installation</b>: A live installation runs the OS from removable media without integrating patches.</span><span class='qd'><b>Bare-metal restore</b>: A bare-metal restore recovers from backup, not a slipstreamed install image.</span><span class='qd'><b>V2V migration</b>: V2V migrates VMs between platforms and is unrelated to slipstreaming.</span>" },
  { id:"D2-010", domain:2, obj:"2.1", diff:"hard", q:"After installing an OS, an admin must choose a remote-management option for secured command-line access to a Linux server. Which is most appropriate?", options:["RDP","VNC","VMFS","SSH"], answer:3, explain:"<strong>SSH</strong> is correct. SSH provides remote, secured command-line administration and is the typical choice for Linux servers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RDP</b>: RDP delivers a remote graphical interface, usually for Windows Server.</span><span class='qd'><b>VNC</b>: VNC provides remote graphical access, not a primarily command-line tool.</span><span class='qd'><b>VMFS</b>: VMFS is a VMware file system, not a remote-administration protocol.</span>" },
  { id:"D2-011", domain:2, obj:"2.1", diff:"medium", q:"A RHEL 8 administrator needs to expand a logical volume by adding a new physical disk without rebooting or repartitioning. Which technology enables this?", options:["Windows Dynamic Disks","MBR primary partitions","LVM (Logical Volume Manager)","A FAT32 extended partition"], answer:2, explain:"<strong>LVM (Logical Volume Manager)</strong> is correct. LVM organizes storage into PVs, VGs, and LVs so a new physical disk can be added and the logical volume extended without a reboot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Windows Dynamic Disks</b>: Dynamic Disks are a Windows feature, not used on RHEL.</span><span class='qd'><b>MBR primary partitions</b>: MBR primary partitions are fixed and cannot be flexibly extended like LVM.</span><span class='qd'><b>A FAT32 extended partition</b>: FAT32 extended partitions provide no online flexible expansion.</span>" },
  { id:"D2-012", domain:2, obj:"2.1", diff:"easy", q:"Which file system is the default for Red Hat Enterprise Linux 8 and is valued for high performance in enterprise environments?", options:["XFS","NTFS","ReFS","FAT32"], answer:0, explain:"<strong>XFS</strong> is correct. XFS is the default file system on RHEL 8 and offers high performance and stability for enterprise servers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>NTFS</b>: NTFS is the primary Windows file system, not a Linux default.</span><span class='qd'><b>ReFS</b>: ReFS is a Windows resilient file system, not used on RHEL.</span><span class='qd'><b>FAT32</b>: FAT32 is an older file system for removable media, not an enterprise Linux default.</span>" },
  { id:"D2-013", domain:2, obj:"2.1", diff:"medium", q:"A Windows administrator wants to format a data volume that supports permissions and BitLocker for a file server. Which file system fits best?", options:["ext4","XFS","NTFS","VMFS"], answer:2, explain:"<strong>NTFS</strong> is correct. NTFS is the primary Windows file system, providing security permissions, stability, and BitLocker support.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ext4</b>: ext4 is a Linux file system not natively used by Windows volumes.</span><span class='qd'><b>XFS</b>: XFS is a Linux file system, not a Windows option.</span><span class='qd'><b>VMFS</b>: VMFS is a VMware file system for VM images, not a Windows data volume.</span>" },
  { id:"D2-014", domain:2, obj:"2.1", diff:"hard", q:"Under MBR, an administrator needs a fourth bootable area but has already created three primary partitions. What is the correct understanding of MBR limits?", options:["MBR allows up to four partitions total, such as three primary plus one extended subdivided into logical partitions","MBR allows unlimited primary partitions","MBR supports drives up to 16 TB","MBR requires UEFI firmware to boot"], answer:0, explain:"<strong>MBR allows up to four partitions total, such as three primary plus one extended subdivided into logical partitions</strong> is correct. MBR recognizes only four partitions total (commonly three primary plus one extended that holds logical partitions).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>MBR allows unlimited primary partitions</b>: MBR does not allow unlimited primaries; it is capped at four partitions total.</span><span class='qd'><b>MBR supports drives up to 16 TB</b>: MBR cannot address drives larger than 2 TB, let alone 16 TB.</span><span class='qd'><b>MBR requires UEFI firmware to boot</b>: MBR uses legacy BIOS; it is GPT that pairs with UEFI.</span>" },
  { id:"D2-015", domain:2, obj:"2.1", diff:"medium", q:"Which Linux command formats a new partition with the XFS file system?", options:["mkfs.xfs /dev/sdb1","mkfs.ext4 /dev/sdb1","useradd /dev/sdb1","lvextend /dev/sdb1"], answer:0, explain:"<strong>mkfs.xfs /dev/sdb1</strong> is correct. mkfs.xfs /dev/sdb1 creates an XFS file system on the specified partition.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mkfs.ext4 /dev/sdb1</b>: mkfs.ext4 formats with ext4, not XFS.</span><span class='qd'><b>useradd /dev/sdb1</b>: useradd creates a user account and does not format storage.</span><span class='qd'><b>lvextend /dev/sdb1</b>: lvextend grows a logical volume but does not create a file system.</span>" },
  { id:"D2-016", domain:2, obj:"2.1", diff:"hard", q:"A VMware ESXi host needs a file system where multiple hosts can access their own VM disk files without locking the entire volume. Which file system is designed for this?", options:["VMFS","NTFS","ext4","ReFS"], answer:0, explain:"<strong>VMFS</strong> is correct. VMFS is optimized for VM disk images and lets multiple hosts read/write their own VM files without locking the whole volume.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>NTFS</b>: NTFS is a Windows file system and is not designed for shared multi-host VM access.</span><span class='qd'><b>ext4</b>: ext4 is a single-host Linux file system, not a clustered VM file system.</span><span class='qd'><b>ReFS</b>: ReFS is a Windows file system and is not the ESXi VM datastore format.</span>" },
  { id:"D2-017", domain:2, obj:"2.2", diff:"easy", q:"What is the correct order of the four-step DHCP lease process?", options:["Discover, Offer, Request, Acknowledge","Offer, Discover, Acknowledge, Request","Request, Discover, Offer, Acknowledge","Discover, Request, Offer, Acknowledge"], answer:0, explain:"<strong>Discover, Offer, Request, Acknowledge</strong> is correct. DHCP follows DORA: the client Discovers, the server Offers, the client Requests, and the server Acknowledges.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Offer, Discover, Acknowledge, Request</b>: The client must Discover before the server can Offer.</span><span class='qd'><b>Request, Discover, Offer, Acknowledge</b>: Discover, not Request, begins the process.</span><span class='qd'><b>Discover, Request, Offer, Acknowledge</b>: The Offer comes before the Request, not after.</span>" },
  { id:"D2-018", domain:2, obj:"2.2", diff:"medium", q:"A workstation shows an IP address of 169.254.12.7 and cannot reach the network. What does this most likely indicate?", options:["The client received a valid public IP address","The client failed to lease an address from the DHCP server and self-assigned an APIPA address","The loopback adapter is misconfigured","The client is using a static IPv6 global unicast address"], answer:1, explain:"<strong>The client failed to lease an address from the DHCP server and self-assigned an APIPA address</strong> is correct. The 169.254.0.0/16 APIPA range is self-assigned when a client cannot reach a DHCP server, signaling a DHCP failure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The client received a valid public IP address</b>: 169.254.x.x is a private self-assigned range, not a routable public address.</span><span class='qd'><b>The loopback adapter is misconfigured</b>: The loopback address is 127.0.0.1, unrelated to 169.254.x.x.</span><span class='qd'><b>The client is using a static IPv6 global unicast address</b>: 169.254.x.x is IPv4 APIPA, not an IPv6 global unicast address.</span>" },
  { id:"D2-019", domain:2, obj:"2.2", diff:"easy", q:"Which DNS record type maps a hostname to an IPv4 address?", options:["MX record","PTR record","AAAA record","A record"], answer:3, explain:"<strong>A record</strong> is correct. An A record maps a hostname to an IPv4 address.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>MX record</b>: An MX record identifies a mail exchanger, not an IPv4 host mapping.</span><span class='qd'><b>PTR record</b>: A PTR record maps an IP address back to a name (reverse lookup).</span><span class='qd'><b>AAAA record</b>: An AAAA record maps a hostname to an IPv6 address, not IPv4.</span>" },
  { id:"D2-020", domain:2, obj:"2.2", diff:"medium", q:"An administrator needs to map a hostname to an IPv6 address in DNS. Which record type is required?", options:["A record","CNAME record","TXT record","AAAA record"], answer:3, explain:"<strong>AAAA record</strong> is correct. An AAAA record maps a hostname to a 128-bit IPv6 address.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A record</b>: An A record maps to an IPv4 address, not IPv6.</span><span class='qd'><b>CNAME record</b>: A CNAME record is an alias to another name, not an address mapping.</span><span class='qd'><b>TXT record</b>: A TXT record holds arbitrary text such as SPF data, not an IPv6 address.</span>" },
  { id:"D2-021", domain:2, obj:"2.2", diff:"medium", q:"Two servers must be on the same logical segment despite being plugged into switches in different parts of the building. What should the administrator configure?", options:["A second default gateway on each host","A larger DHCP scope","A host file entry on each server","A VLAN spanning the switches"], answer:3, explain:"<strong>A VLAN spanning the switches</strong> is correct. VLANs segment networks on a per-port basis and can span multiple switches, placing physically separated hosts on one logical segment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A second default gateway on each host</b>: Adding default gateways does not place hosts on the same logical segment.</span><span class='qd'><b>A larger DHCP scope</b>: Enlarging a DHCP scope assigns addresses but does not create a shared segment.</span><span class='qd'><b>A host file entry on each server</b>: Hosts file entries resolve names; they do not create network segments.</span>" },
  { id:"D2-022", domain:2, obj:"2.2", diff:"hard", q:"A host has IP 192.168.2.200 with mask 255.255.255.0. What is the network ID?", options:["192.168.0.0","192.168.2.200","192.168.2.0","0.0.0.200"], answer:2, explain:"<strong>192.168.2.0</strong> is correct. With a /24 mask the first three octets are the network ID, so 192.168.2.200 yields network 192.168.2.0.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>192.168.0.0</b>: 192.168.0.0 would require a /16 mask, not /24.</span><span class='qd'><b>192.168.2.200</b>: 192.168.2.200 is the full host address, not the network ID.</span><span class='qd'><b>0.0.0.200</b>: 0.0.0.200 is the host portion, not the network ID.</span>" },
  { id:"D2-023", domain:2, obj:"2.2", diff:"easy", q:"Which port and protocol does HTTPS use?", options:["80/tcp","53/udp","443/tcp","22/tcp"], answer:2, explain:"<strong>443/tcp</strong> is correct. HTTPS uses TCP port 443.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>80/tcp</b>: 80/tcp is HTTP, the unencrypted web protocol.</span><span class='qd'><b>53/udp</b>: 53/udp is DNS, not HTTPS.</span><span class='qd'><b>22/tcp</b>: 22/tcp is SSH, not HTTPS.</span>" },
  { id:"D2-024", domain:2, obj:"2.2", diff:"medium", q:"A firewall log shows traffic to port 53 being allowed. Which service is most likely being permitted?", options:["DNS name resolution","HTTPS web traffic","RDP remote desktop","SMTP email relay"], answer:0, explain:"<strong>DNS name resolution</strong> is correct. DNS uses port 53 (TCP and UDP), so allowing port 53 permits name-resolution traffic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>HTTPS web traffic</b>: HTTPS uses port 443, not 53.</span><span class='qd'><b>RDP remote desktop</b>: RDP uses port 3389, not 53.</span><span class='qd'><b>SMTP email relay</b>: SMTP uses port 25, not 53.</span>" },
  { id:"D2-025", domain:2, obj:"2.2", diff:"medium", q:"Why do servers typically use static IP addresses rather than DHCP-assigned ones?", options:["DHCP cannot assign addresses to servers","Static addresses are required for APIPA to function","Clients reference servers by a consistent, unchanging address","Static addresses eliminate the need for a subnet mask"], answer:2, explain:"<strong>Clients reference servers by a consistent, unchanging address</strong> is correct. Servers need a consistent, unchanging address so clients can reliably locate them, which is why static addressing is used.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DHCP cannot assign addresses to servers</b>: DHCP can assign server addresses (e.g., reservations); it is just less desirable for servers.</span><span class='qd'><b>Static addresses are required for APIPA to function</b>: APIPA is a fallback for DHCP failure and is unrelated to static addressing.</span><span class='qd'><b>Static addresses eliminate the need for a subnet mask</b>: Every IPv4 host, static or not, still needs a subnet mask.</span>" },
  { id:"D2-026", domain:2, obj:"2.2", diff:"hard", q:"An internal host with private IP 192.168.2.200 needs to reach a public website. Which service allows this by substituting the organization's public IP?", options:["DHCP","NAT (Network Address Translation)","APIPA","VLAN tagging"], answer:1, explain:"<strong>NAT (Network Address Translation)</strong> is correct. NAT substitutes a public IP for traffic from private RFC 1918 addresses, allowing internal hosts to reach the Internet.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DHCP</b>: DHCP assigns addresses; it does not translate between private and public IPs.</span><span class='qd'><b>APIPA</b>: APIPA is a self-assigned fallback range, not a translation service.</span><span class='qd'><b>VLAN tagging</b>: VLAN tagging segments switch ports and does not perform address translation.</span>" },
  { id:"D2-027", domain:2, obj:"2.2", diff:"easy", q:"Which reserved IPv4 range is the Class A private address space defined by RFC 1918?", options:["172.16.0.0 - 172.31.255.255","10.0.0.0 - 10.255.255.255","192.168.0.0 - 192.168.255.255","169.254.0.0 - 169.254.255.255"], answer:1, explain:"<strong>10.0.0.0 - 10.255.255.255</strong> is correct. The Class A private range is 10.0.0.0 through 10.255.255.255.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>172.16.0.0 - 172.31.255.255</b>: 172.16.0.0-172.31.255.255 is the Class B private range, not Class A.</span><span class='qd'><b>192.168.0.0 - 192.168.255.255</b>: 192.168.0.0-192.168.255.255 is the Class C private range.</span><span class='qd'><b>169.254.0.0 - 169.254.255.255</b>: 169.254.0.0/16 is the APIPA range, not an RFC 1918 Class A range.</span>" },
  { id:"D2-028", domain:2, obj:"2.2", diff:"medium", q:"What value tells a host the IP address of the router it should use to reach other network segments?", options:["Subnet mask","DNS server address","Default gateway","MAC address"], answer:2, explain:"<strong>Default gateway</strong> is correct. The default gateway is the router NIC address a host uses to send traffic off its local segment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Subnet mask</b>: The subnet mask separates network and host portions but is not the router address.</span><span class='qd'><b>DNS server address</b>: The DNS server resolves names; it is not the exit router.</span><span class='qd'><b>MAC address</b>: A MAC address is a layer 2 physical identifier, not a gateway.</span>" },
  { id:"D2-029", domain:2, obj:"2.2", diff:"hard", q:"An administrator must decide between subnets and VLANs. Which statement is accurate?", options:["Subnets divide a network using switches, while VLANs use routers","Both subnets and VLANs operate only at layer 1","Subnets divide a network using routers, while VLANs divide it using switches","VLANs require all member hosts to share one physical switch"], answer:2, explain:"<strong>Subnets divide a network using routers, while VLANs divide it using switches</strong> is correct. Subnets are router-based divisions, whereas VLANs are switch-based divisions configured per port.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Subnets divide a network using switches, while VLANs use routers</b>: This reverses the roles; subnets are router-based and VLANs are switch-based.</span><span class='qd'><b>Both subnets and VLANs operate only at layer 1</b>: Subnetting is layer 3 and VLANs are layer 2; neither is purely layer 1.</span><span class='qd'><b>VLANs require all member hosts to share one physical switch</b>: VLANs can span multiple switches, so members need not share one switch.</span>" },
  { id:"D2-030", domain:2, obj:"2.2", diff:"easy", q:"Which IPv4 address is the loopback used to test the local TCP/IP stack?", options:["127.0.0.1","169.254.0.1","192.168.0.1","10.0.0.1"], answer:0, explain:"<strong>127.0.0.1</strong> is correct. 127.0.0.1 is the loopback address that refers a host to itself for troubleshooting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>169.254.0.1</b>: 169.254.0.1 is in the APIPA range, not loopback.</span><span class='qd'><b>192.168.0.1</b>: 192.168.0.1 is a common private gateway address, not loopback.</span><span class='qd'><b>10.0.0.1</b>: 10.0.0.1 is a private Class A address, not the loopback.</span>" },
  { id:"D2-031", domain:2, obj:"2.2", diff:"medium", q:"Which protocol and port pair is correct for SSH?", options:["23/tcp","25/tcp","21/tcp","22/tcp"], answer:3, explain:"<strong>22/tcp</strong> is correct. SSH uses TCP port 22 for secure remote access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>23/tcp</b>: 23/tcp is Telnet, the insecure predecessor to SSH.</span><span class='qd'><b>25/tcp</b>: 25/tcp is SMTP for email, not SSH.</span><span class='qd'><b>21/tcp</b>: 21/tcp is FTP control, not SSH.</span>" },
  { id:"D2-032", domain:2, obj:"2.3", diff:"easy", q:"An administrator wants to compare current server performance to its expected normal state after a change. Which reference is most useful?", options:["The vendor's marketing datasheet","A performance baseline captured during deployment","A random sample from another server model","The server's BIOS version string"], answer:1, explain:"<strong>A performance baseline captured during deployment</strong> is correct. A baseline captured during deployment provides the normal performance reference to compare against after changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The vendor's marketing datasheet</b>: A marketing datasheet describes theoretical specs, not this server's real baseline.</span><span class='qd'><b>A random sample from another server model</b>: Another model's sample is not comparable to this server's behavior.</span><span class='qd'><b>The server's BIOS version string</b>: A BIOS version string says nothing about performance levels.</span>" },
  { id:"D2-033", domain:2, obj:"2.3", diff:"medium", q:"A monitoring system polls network devices for status using UDP port 161. Which protocol is in use?", options:["NTP","SNMP","SMTP","TFTP"], answer:1, explain:"<strong>SNMP</strong> is correct. SNMP uses UDP port 161 to poll and monitor network device status.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>NTP</b>: NTP uses UDP 123 for time synchronization, not monitoring polls.</span><span class='qd'><b>SMTP</b>: SMTP uses TCP 25 for email, not device monitoring.</span><span class='qd'><b>TFTP</b>: TFTP uses UDP 69 for simple file transfer, not status polling.</span>" },
  { id:"D2-034", domain:2, obj:"2.3", diff:"medium", q:"Which Linux service collects and stores system log files for later review during troubleshooting?", options:["Event Viewer","Task Scheduler","Server Manager","rsyslog"], answer:3, explain:"<strong>rsyslog</strong> is correct. On Linux, rsyslog is the logging service that records system events for review.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Event Viewer</b>: Event Viewer is the Windows log service, not Linux.</span><span class='qd'><b>Task Scheduler</b>: Task Scheduler runs scheduled jobs on Windows, not logging.</span><span class='qd'><b>Server Manager</b>: Server Manager is a Windows management console, not a log service.</span>" },
  { id:"D2-035", domain:2, obj:"2.3", diff:"easy", q:"Which Windows tool is used to review logged system, application, and security events?", options:["Event Viewer","rsyslog","cron","vSphere"], answer:0, explain:"<strong>Event Viewer</strong> is correct. Event Viewer is the Windows service for reviewing logged system, application, and security events.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rsyslog</b>: rsyslog is the Linux logging service, not a Windows tool.</span><span class='qd'><b>cron</b>: cron is the Linux job scheduler, not a log viewer.</span><span class='qd'><b>vSphere</b>: vSphere is VMware management software, not a Windows event log.</span>" },
  { id:"D2-036", domain:2, obj:"2.7", diff:"medium", q:"An organization must track which licenses, warranties, and hardware are deployed across the data center. This practice is called what?", options:["Capacity planning","Root cause analysis","Load balancing","Asset management"], answer:3, explain:"<strong>Asset management</strong> is correct. Asset management tracks hardware, licenses, warranties, and other deployed inventory.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Capacity planning</b>: Capacity planning forecasts future resource needs, not current inventory tracking.</span><span class='qd'><b>Root cause analysis</b>: Root cause analysis investigates why a problem occurred.</span><span class='qd'><b>Load balancing</b>: Load balancing distributes traffic across servers.</span>" },
  { id:"D2-037", domain:2, obj:"2.3", diff:"hard", q:"Monitoring shows a server's CPU pegged near 100% over several days, threatening service levels. Which proactive practice does this support?", options:["Performing a P2V migration","Rotating the firewall rules","Changing the DNS record type","Capacity planning for future resource growth"], answer:3, explain:"<strong>Capacity planning for future resource growth</strong> is correct. Sustained high utilization data feeds capacity planning so resources can be scaled before service levels are breached.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Performing a P2V migration</b>: A P2V migration converts physical to virtual and does not by itself address capacity forecasting.</span><span class='qd'><b>Rotating the firewall rules</b>: Rotating firewall rules is a security task unrelated to CPU capacity.</span><span class='qd'><b>Changing the DNS record type</b>: Changing a DNS record type does not address server CPU exhaustion.</span>" },
  { id:"D2-038", domain:2, obj:"2.7", diff:"medium", q:"An administrator must demonstrate to an auditor that installed software counts match purchased licenses. What is this called?", options:["Slipstreaming","Overprovisioning","License count validation","Failover testing"], answer:2, explain:"<strong>License count validation</strong> is correct. License count validation proves that the number of installations or users matches the license entitlements during an audit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slipstreaming</b>: Slipstreaming integrates patches into an install image, unrelated to audits.</span><span class='qd'><b>Overprovisioning</b>: Overprovisioning adds extra hardware capacity, not license proof.</span><span class='qd'><b>Failover testing</b>: Failover testing verifies redundancy, not license compliance.</span>" },
  { id:"D2-039", domain:2, obj:"2.7", diff:"easy", q:"A sysadmin documents symptoms, actions taken, and outcomes at every troubleshooting phase. Why is this important?", options:["It is only required to satisfy hardware vendors","It builds knowledge of the environment and helps prevent future problems","It replaces the need to verify functionality","It eliminates the need for a baseline"], answer:1, explain:"<strong>It builds knowledge of the environment and helps prevent future problems</strong> is correct. Documenting findings and outcomes throughout improves understanding of the environment and helps prevent recurrences.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is only required to satisfy hardware vendors</b>: Documentation serves the organization, not merely hardware vendors.</span><span class='qd'><b>It replaces the need to verify functionality</b>: Documentation does not replace verifying full system functionality.</span><span class='qd'><b>It eliminates the need for a baseline</b>: Documentation complements, but does not eliminate, a performance baseline.</span>" },
  { id:"D2-040", domain:2, obj:"2.3", diff:"medium", q:"After resolving an outage, the administrator investigates why it happened to prevent recurrence. Which troubleshooting step is this?", options:["Perform a root cause analysis","Establish a theory of probable cause","Determine the scope of the problem","Implement the solution"], answer:0, explain:"<strong>Perform a root cause analysis</strong> is correct. Root cause analysis evaluates why the problem occurred so processes or technologies can be changed to avoid it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Establish a theory of probable cause</b>: Establishing a theory happens early, before the fix is implemented.</span><span class='qd'><b>Determine the scope of the problem</b>: Determining scope happens during problem identification, not after resolution.</span><span class='qd'><b>Implement the solution</b>: Implementing the solution is the fix step, not the after-the-fact analysis.</span>" },
  { id:"D2-041", domain:2, obj:"2.4", diff:"easy", q:"In an active/passive cluster, what is the role of the passive node?", options:["It shares the workload equally with the active node at all times","It serves read-only traffic while the active node serves writes","It is powered off and cannot be brought online","It stands by and takes over only if the active node fails"], answer:3, explain:"<strong>It stands by and takes over only if the active node fails</strong> is correct. In active/passive clustering the passive node is on standby and assumes the workload only when the active node fails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It shares the workload equally with the active node at all times</b>: Sharing the workload equally describes active/active, not active/passive.</span><span class='qd'><b>It serves read-only traffic while the active node serves writes</b>: Splitting reads and writes is not the defining behavior of active/passive failover.</span><span class='qd'><b>It is powered off and cannot be brought online</b>: The passive node is online and ready, not powered off.</span>" },
  { id:"D2-042", domain:2, obj:"2.4", diff:"medium", q:"An administrator wants both cluster nodes processing requests simultaneously to maximize throughput. Which configuration is this?", options:["Active/passive","Cold standby","Active/active","N+1 with all spares idle"], answer:2, explain:"<strong>Active/active</strong> is correct. Active/active has all nodes processing requests at once, maximizing throughput and using all hardware.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Active/passive</b>: Active/passive keeps one node idle until failover, not processing simultaneously.</span><span class='qd'><b>Cold standby</b>: Cold standby keeps the backup powered off until needed.</span><span class='qd'><b>N+1 with all spares idle</b>: Idle spares do not process requests, so throughput is not maximized.</span>" },
  { id:"D2-043", domain:2, obj:"2.4", diff:"medium", q:"A load balancer distributes incoming web requests across several identical servers. What is the primary benefit?", options:["Guaranteed elimination of all single points of failure in the database","Reduced need for any server patching","Improved availability and the ability to handle more concurrent load","Automatic conversion of physical servers to VMs"], answer:2, explain:"<strong>Improved availability and the ability to handle more concurrent load</strong> is correct. Load balancing spreads requests across multiple servers, improving availability and supporting more concurrent load.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Guaranteed elimination of all single points of failure in the database</b>: A web load balancer does not by itself remove database single points of failure.</span><span class='qd'><b>Reduced need for any server patching</b>: Load balancing does not remove the need to patch the servers.</span><span class='qd'><b>Automatic conversion of physical servers to VMs</b>: Load balancing does not perform P2V conversions.</span>" },
  { id:"D2-044", domain:2, obj:"2.4", diff:"hard", q:"A virtualization cluster replicates VMs to a second host so guests survive a host failure. Which goal does this primarily serve?", options:["License count validation","High availability","Network address translation","Slipstream installation"], answer:1, explain:"<strong>High availability</strong> is correct. Replicating VMs between hosts so guests survive a host failure is a high-availability measure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>License count validation</b>: License count validation concerns audit compliance, not HA replication.</span><span class='qd'><b>Network address translation</b>: NAT translates addresses and is unrelated to VM replication.</span><span class='qd'><b>Slipstream installation</b>: Slipstreaming integrates patches into install media, not HA.</span>" },
  { id:"D2-045", domain:2, obj:"2.4", diff:"easy", q:"A single virtualization host running many VMs represents what risk that high availability addresses?", options:["Excessive licensing discounts","Too many available IP addresses","An overly small server footprint","A single point of failure affecting every guest VM"], answer:3, explain:"<strong>A single point of failure affecting every guest VM</strong> is correct. A lone host is a single point of failure that would take down all its guests, which HA designs aim to mitigate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Excessive licensing discounts</b>: Licensing discounts are not a failure risk.</span><span class='qd'><b>Too many available IP addresses</b>: Having many IP addresses is not the risk HA addresses here.</span><span class='qd'><b>An overly small server footprint</b>: A small footprint is not the single-point-of-failure concern.</span>" },
  { id:"D2-046", domain:2, obj:"2.4", diff:"medium", q:"To survive the loss of a power supply, NIC, or disk inside a virtualization host, what should the host include?", options:["A single high-speed NIC only","MBR partitioning","A Type 2 hypervisor","Redundant hardware components"], answer:3, explain:"<strong>Redundant hardware components</strong> is correct. Redundant hardware (multiple power supplies, NICs, and disks) keeps a host available when an individual component fails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single high-speed NIC only</b>: A single NIC provides no redundancy if it fails.</span><span class='qd'><b>MBR partitioning</b>: MBR partitioning is a disk layout choice, not hardware redundancy.</span><span class='qd'><b>A Type 2 hypervisor</b>: A Type 2 hypervisor choice does not by itself add hardware redundancy.</span>" },
  { id:"D2-047", domain:2, obj:"2.4", diff:"hard", q:"An administrator combines multiple NICs so a host has more aggregate bandwidth and survives a single NIC failure. What is this called?", options:["NIC teaming","Overcommitting RAM","VLAN trunking","Disk striping"], answer:0, explain:"<strong>NIC teaming</strong> is correct. NIC teaming combines multiple NICs to increase aggregate bandwidth and provide redundancy if one NIC fails.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Overcommitting RAM</b>: Overcommitting RAM allocates more memory than physically present, not NIC bonding.</span><span class='qd'><b>VLAN trunking</b>: VLAN trunking carries multiple VLANs on a link, not NIC aggregation for redundancy.</span><span class='qd'><b>Disk striping</b>: Disk striping spreads data across disks, unrelated to NICs.</span>" },
  { id:"D2-048", domain:2, obj:"2.4", diff:"medium", q:"Which approach keeps geographically separated copies of data so a regional outage does not cause data loss?", options:["Geo-redundancy across multiple sites","A single on-premises RAID 0 array","Storing all data on one host's local disk","Disabling backups to save space"], answer:0, explain:"<strong>Geo-redundancy across multiple sites</strong> is correct. Geo-redundancy keeps copies in separate locations so a regional outage does not destroy the only copy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single on-premises RAID 0 array</b>: RAID 0 has no redundancy and is in one location.</span><span class='qd'><b>Storing all data on one host's local disk</b>: A single host's local disk is one point of failure.</span><span class='qd'><b>Disabling backups to save space</b>: Disabling backups increases, not decreases, the risk of data loss.</span>" },
  { id:"D2-049", domain:2, obj:"2.5", diff:"easy", q:"Which hypervisor type installs directly on the physical hardware without an underlying OS?", options:["Type 2 (hosted) hypervisor","Type 1 (bare-metal) hypervisor","A container runtime","A Type 3 hypervisor"], answer:1, explain:"<strong>Type 1 (bare-metal) hypervisor</strong> is correct. A Type 1 hypervisor installs directly on hardware and acts as its own OS; examples include ESXi, Hyper-V, and KVM.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Type 2 (hosted) hypervisor</b>: A Type 2 hypervisor runs on top of a traditional host OS.</span><span class='qd'><b>A container runtime</b>: A container runtime shares the host kernel and is not a Type 1 hypervisor.</span><span class='qd'><b>A Type 3 hypervisor</b>: There is no standard Type 3 hypervisor category.</span>" },
  { id:"D2-050", domain:2, obj:"2.5", diff:"easy", q:"Which is an example of a Type 2 hypervisor suitable for a developer's workstation?", options:["VMware ESXi","VMware Workstation","Microsoft Hyper-V (bare metal)","KVM"], answer:1, explain:"<strong>VMware Workstation</strong> is correct. VMware Workstation is a Type 2 hypervisor that runs on top of a desktop OS, ideal for developers and testing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>VMware ESXi</b>: ESXi is a Type 1 bare-metal hypervisor.</span><span class='qd'><b>Microsoft Hyper-V (bare metal)</b>: Hyper-V as a bare-metal role is a Type 1 hypervisor.</span><span class='qd'><b>KVM</b>: KVM is a Type 1 Linux kernel hypervisor.</span>" },
  { id:"D2-051", domain:2, obj:"2.5", diff:"medium", q:"A company wants to use VMs hosted in a provider's data center while installing and maintaining the guest OS and apps themselves. Which cloud service model fits?", options:["PaaS (Platform as a Service)","SaaS (Software as a Service)","IaaS (Infrastructure as a Service)","Community cloud"], answer:2, explain:"<strong>IaaS (Infrastructure as a Service)</strong> is correct. IaaS provides provider-maintained hardware/VMs while the customer installs and maintains the OS and applications.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>PaaS (Platform as a Service)</b>: PaaS provides a managed platform; the customer does not manage the OS.</span><span class='qd'><b>SaaS (Software as a Service)</b>: SaaS delivers finished software with no OS or app maintenance by the customer.</span><span class='qd'><b>Community cloud</b>: Community cloud is a deployment model, not a service model.</span>" },
  { id:"D2-052", domain:2, obj:"2.5", diff:"medium", q:"Developers need a managed database and runtime environment without managing the underlying OS or hardware. Which cloud service model is this?", options:["IaaS (Infrastructure as a Service)","SaaS (Software as a Service)","Private cloud","PaaS (Platform as a Service)"], answer:3, explain:"<strong>PaaS (Platform as a Service)</strong> is correct. PaaS supplies a managed platform such as databases and development environments while the provider handles the OS and hardware.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IaaS (Infrastructure as a Service)</b>: IaaS requires the customer to manage the OS, which they want to avoid.</span><span class='qd'><b>SaaS (Software as a Service)</b>: SaaS delivers finished applications, not a development platform.</span><span class='qd'><b>Private cloud</b>: Private cloud is a deployment model, not a service model.</span>" },
  { id:"D2-053", domain:2, obj:"2.5", diff:"easy", q:"Microsoft Office 365 and Google Docs are examples of which cloud service model?", options:["IaaS (Infrastructure as a Service)","SaaS (Software as a Service)","PaaS (Platform as a Service)","Hybrid cloud"], answer:1, explain:"<strong>SaaS (Software as a Service)</strong> is correct. Office 365 and Google Docs are finished applications delivered as SaaS, with the vendor maintaining everything beneath.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IaaS (Infrastructure as a Service)</b>: IaaS provides raw VMs, not finished applications.</span><span class='qd'><b>PaaS (Platform as a Service)</b>: PaaS provides development platforms, not end-user apps.</span><span class='qd'><b>Hybrid cloud</b>: Hybrid cloud is a deployment model, not a service model.</span>" },
  { id:"D2-054", domain:2, obj:"2.5", diff:"medium", q:"An organization uses both an on-premises private cloud for sensitive data and a public cloud for other workloads. Which deployment model is this?", options:["Hybrid cloud","Public cloud","Community cloud","Private cloud"], answer:0, explain:"<strong>Hybrid cloud</strong> is correct. Combining private and public cloud deployments is a hybrid cloud model.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Public cloud</b>: A pure public cloud would not include the private on-premises portion.</span><span class='qd'><b>Community cloud</b>: A community cloud is shared among several similar organizations, not this mix.</span><span class='qd'><b>Private cloud</b>: A pure private cloud would exclude the public workloads.</span>" },
  { id:"D2-055", domain:2, obj:"2.5", diff:"hard", q:"Several hospitals with similar regulatory requirements jointly fund and share a single secured cloud. Which deployment model is this?", options:["Public cloud","Private cloud","Hybrid cloud","Community cloud"], answer:3, explain:"<strong>Community cloud</strong> is correct. A community cloud is shared by multiple organizations with similar requirements that jointly support it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Public cloud</b>: A public cloud shares resources with the general customer base, not a closed group.</span><span class='qd'><b>Private cloud</b>: A private cloud serves a single organization exclusively.</span><span class='qd'><b>Hybrid cloud</b>: A hybrid cloud combines models rather than a shared community deployment.</span>" },
  { id:"D2-056", domain:2, obj:"2.5", diff:"medium", q:"Under the cloud shared security model, which responsibility belongs to the customer rather than the CSP?", options:["Physical security of the data center","Securing the data placed in the cloud","Maintaining the hardware availability","Powering and cooling the facility"], answer:1, explain:"<strong>Securing the data placed in the cloud</strong> is correct. In the shared security model the customer secures its data in the cloud, while the CSP secures the underlying facility and hardware.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Physical security of the data center</b>: Physical data-center security is the CSP's responsibility.</span><span class='qd'><b>Maintaining the hardware availability</b>: Hardware availability is maintained by the CSP.</span><span class='qd'><b>Powering and cooling the facility</b>: Facility power and cooling are the CSP's responsibility.</span>" },
  { id:"D2-057", domain:2, obj:"2.5", diff:"easy", q:"Which NIST cloud characteristic describes resources scaling up and down as demand changes so consumers pay for what they use?", options:["Broad network access","Resource pooling","Rapid elasticity","Measured service"], answer:2, explain:"<strong>Rapid elasticity</strong> is correct. Rapid elasticity lets resources scale up and down with demand so consumers pay only for what they need.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Broad network access</b>: Broad network access is about reaching services from many device types.</span><span class='qd'><b>Resource pooling</b>: Resource pooling describes shared resources allocated to tenants.</span><span class='qd'><b>Measured service</b>: Measured service is about metering and billing based on use.</span>" },
  { id:"D2-058", domain:2, obj:"2.5", diff:"medium", q:"A VM must communicate only with other VMs on the same host and have no access to the physical network. Which virtual network mode fits?", options:["Local (internal only) networking","Bridged networking","NAT to the public Internet","A teamed physical NIC"], answer:0, explain:"<strong>Local (internal only) networking</strong> is correct. Local networking limits a VM to communicating only with other VMs on the same host, isolating it from the physical network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bridged networking</b>: Bridged networking exposes the VM directly on the physical network.</span><span class='qd'><b>NAT to the public Internet</b>: NAT to the Internet gives outbound public access, which is not wanted here.</span><span class='qd'><b>A teamed physical NIC</b>: A teamed physical NIC increases host bandwidth, not VM isolation.</span>" },
  { id:"D2-059", domain:2, obj:"2.5", diff:"hard", q:"An administrator deliberately allocates more total vCPU to VMs than the host physically has, relying on idle time. What is this practice and its key requirement?", options:["Underprovisioning, which guarantees idle CPUs","Bare-metal installation, which prevents sharing","NIC teaming, which adds CPU cores","Over-allocation, which requires careful monitoring to avoid degrading performance"], answer:3, explain:"<strong>Over-allocation, which requires careful monitoring to avoid degrading performance</strong> is correct. Over-allocating CPU leverages idle time but requires close monitoring so the host and guests are not degraded.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Underprovisioning, which guarantees idle CPUs</b>: Underprovisioning is the opposite and does not describe this.</span><span class='qd'><b>Bare-metal installation, which prevents sharing</b>: Bare-metal installs avoid sharing entirely, contradicting over-allocation.</span><span class='qd'><b>NIC teaming, which adds CPU cores</b>: NIC teaming combines NICs and adds no CPU cores.</span>" },
  { id:"D2-060", domain:2, obj:"2.5", diff:"easy", q:"A VM acting as a production DNS server must appear as a normal node on the physical network. Which virtual network mode is appropriate?", options:["Bridged networking","Host-only networking","None (no NIC)","Local networking"], answer:0, explain:"<strong>Bridged networking</strong> is correct. Bridged networking lets a VM participate directly on the physical network like any normal node, suitable for production DNS.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Host-only networking</b>: Host-only restricts the VM to the host, not the physical network.</span><span class='qd'><b>None (no NIC)</b>: None means no NIC, so the VM has no connectivity.</span><span class='qd'><b>Local networking</b>: Local limits the VM to other VMs on the host.</span>" },
  { id:"D2-061", domain:2, obj:"2.5", diff:"medium", q:"Which statement about cloud deployments versus on-premises is accurate?", options:["Cloud always reduces operating expenditures to zero","On-premises always deploys faster than cloud","Cloud uses a pay-as-you-go model and scales easily, but the organization gives up some control","On-premises removes the need to secure data"], answer:2, explain:"<strong>Cloud uses a pay-as-you-go model and scales easily, but the organization gives up some control</strong> is correct. Cloud offers pay-as-you-go billing and easy scaling at the cost of reduced control over the environment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cloud always reduces operating expenditures to zero</b>: Cloud can raise OpEx; it does not reduce operating costs to zero.</span><span class='qd'><b>On-premises always deploys faster than cloud</b>: Cloud typically deploys faster than on-premises, not the reverse.</span><span class='qd'><b>On-premises removes the need to secure data</b>: On-premises still requires the organization to secure its data.</span>" },
  { id:"D2-062", domain:2, obj:"2.6", diff:"easy", q:"Which character begins a comment line in a bash script, causing the system to ignore that line?", options:["//","#","/*","REM"], answer:1, explain:"<strong>#</strong> is correct. In bash, lines beginning with # are comments and are ignored by the interpreter.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>//</b>: // begins comments in C-style languages, not bash.</span><span class='qd'><b>/*</b>: /* begins block comments in C-style languages, not bash.</span><span class='qd'><b>REM</b>: REM is the comment keyword in MS-DOS batch files, not bash.</span>" },
  { id:"D2-063", domain:2, obj:"2.6", diff:"medium", q:"Which shell is the default scripting environment on Linux servers?", options:["bash (Bourne Again Shell)","PowerShell","cmd.exe","VBScript"], answer:0, explain:"<strong>bash (Bourne Again Shell)</strong> is correct. bash is the default Linux shell used for scripting on Linux servers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>PowerShell</b>: PowerShell is Microsoft's emphasized Windows shell, not the Linux default.</span><span class='qd'><b>cmd.exe</b>: cmd.exe is a Windows command shell.</span><span class='qd'><b>VBScript</b>: VBScript is a deprecated Windows scripting language.</span>" },
  { id:"D2-064", domain:2, obj:"2.6", diff:"medium", q:"A bash script must repeat a block as long as a condition remains true. Which construct fits?", options:["An until loop","An if conditional","A function definition","A while loop"], answer:3, explain:"<strong>A while loop</strong> is correct. A while loop repeats as long as its condition evaluates to true.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An until loop</b>: An until loop repeats while the condition is false, the opposite behavior.</span><span class='qd'><b>An if conditional</b>: An if conditional runs a block once based on a test, it does not loop.</span><span class='qd'><b>A function definition</b>: A function defines reusable code but does not by itself loop.</span>" },
  { id:"D2-065", domain:2, obj:"2.6", diff:"hard", q:"In a bash comparison, which operator tests whether one integer is greater than another?", options:["-eq","-lt","-ne","-gt"], answer:3, explain:"<strong>-gt</strong> is correct. The -gt operator tests whether the left integer is greater than the right.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>-eq</b>: -eq tests equality, not greater-than.</span><span class='qd'><b>-lt</b>: -lt tests less-than, the opposite comparison.</span><span class='qd'><b>-ne</b>: -ne tests inequality, not greater-than.</span>" },
  { id:"D2-066", domain:2, obj:"2.6", diff:"easy", q:"Which scripting language does Microsoft emphasize for automating Windows server administration?", options:["PowerShell","bash","VBScript","Python only"], answer:0, explain:"<strong>PowerShell</strong> is correct. Microsoft emphasizes PowerShell for Windows server automation; its commands are called cmdlets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>bash</b>: bash is primarily a Linux shell.</span><span class='qd'><b>VBScript</b>: VBScript is deprecated by Microsoft.</span><span class='qd'><b>Python only</b>: Windows is not limited to Python; PowerShell is the emphasized shell.</span>" },
  { id:"D2-067", domain:2, obj:"2.6", diff:"medium", q:"A script needs to store and reference 100 server names efficiently rather than creating 100 separate variables. Which data type fits?", options:["An array","An integer","A single string","A boolean"], answer:0, explain:"<strong>An array</strong> is correct. An array stores a list of like values, ideal for referencing 100 server names without separate variables.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An integer</b>: An integer holds a single whole number, not a list.</span><span class='qd'><b>A single string</b>: A single string holds one sequence of characters, not 100 indexed values efficiently.</span><span class='qd'><b>A boolean</b>: A boolean holds only true or false.</span>" },
  { id:"D2-068", domain:2, obj:"2.6", diff:"medium", q:"Which bash environment variable references the currently logged-in user so a backup script works for any user?", options:["$HOSTNAME","$HOME","$PATH","$USER"], answer:3, explain:"<strong>$USER</strong> is correct. $USER holds the currently logged-in username, letting a script act on whoever runs it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>$HOSTNAME</b>: $HOSTNAME holds the system name, not the user.</span><span class='qd'><b>$HOME</b>: $HOME holds the user's home directory path, not the username itself.</span><span class='qd'><b>$PATH</b>: $PATH lists executable search directories, not the user.</span>" },
  { id:"D2-069", domain:2, obj:"2.6", diff:"hard", q:"An administrator wants a script to back up a directory automatically at 2 a.m. nightly on Linux. Which utility schedules it?", options:["Task Scheduler","Event Viewer","rsyslog","cron"], answer:3, explain:"<strong>cron</strong> is correct. cron schedules recurring jobs on Linux, such as a nightly 2 a.m. backup script.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Task Scheduler</b>: Task Scheduler is the Windows scheduling utility, not Linux.</span><span class='qd'><b>Event Viewer</b>: Event Viewer reviews Windows logs and does not schedule jobs.</span><span class='qd'><b>rsyslog</b>: rsyslog collects Linux logs and does not schedule scripts.</span>" },
  { id:"D2-070", domain:2, obj:"2.6", diff:"easy", q:"Before a Linux script can be run by the system rather than just read, what must be set on the file?", options:["A static IP address","An NTFS ACL","The executable permission","A DHCP reservation"], answer:2, explain:"<strong>The executable permission</strong> is correct. A Linux script must be given executable permission so the system processes it as a program.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A static IP address</b>: A static IP address is a network setting unrelated to script execution.</span><span class='qd'><b>An NTFS ACL</b>: NTFS ACLs are Windows file permissions, not Linux executable bits.</span><span class='qd'><b>A DHCP reservation</b>: A DHCP reservation assigns an IP and has nothing to do with script execution.</span>" },
  { id:"D2-071", domain:2, obj:"2.6", diff:"medium", q:"Which Windows utility schedules a PowerShell script to run automatically at a set time?", options:["Task Scheduler","cron","useradd","vSphere"], answer:0, explain:"<strong>Task Scheduler</strong> is correct. Task Scheduler is the Windows tool that runs scripts automatically at scheduled times.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cron</b>: cron is the Linux scheduler, not Windows.</span><span class='qd'><b>useradd</b>: useradd is a Linux user-creation command, not a scheduler.</span><span class='qd'><b>vSphere</b>: vSphere is VMware management software, not a Windows scheduler.</span>" },
  { id:"D2-072", domain:2, obj:"2.2", diff:"medium", q:"Which protocol and port handles DHCP server requests from clients?", options:["53/udp","80/tcp","67/udp","123/udp"], answer:2, explain:"<strong>67/udp</strong> is correct. DHCP servers use UDP port 67 to receive client requests.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>53/udp</b>: 53/udp is DNS, not DHCP.</span><span class='qd'><b>80/tcp</b>: 80/tcp is HTTP, not DHCP.</span><span class='qd'><b>123/udp</b>: 123/udp is NTP, not DHCP.</span>" },
  { id:"D2-073", domain:2, obj:"2.2", diff:"hard", q:"An administrator wants a static name-to-IP mapping on one workstation for an isolated dev server not registered in DNS. Which solution is appropriate?", options:["Create a new DHCP scope","Add an entry to the local hosts file","Add an MX record to public DNS","Assign an APIPA address"], answer:1, explain:"<strong>Add an entry to the local hosts file</strong> is correct. A local hosts file entry resolves the isolated server by name on just that workstation without DNS registration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Create a new DHCP scope</b>: A DHCP scope assigns addresses, it does not provide name resolution.</span><span class='qd'><b>Add an MX record to public DNS</b>: An MX record routes mail and would publish the server publicly, which is unwanted.</span><span class='qd'><b>Assign an APIPA address</b>: APIPA is a self-assigned fallback address, not a name-resolution method.</span>" },
  { id:"D2-074", domain:2, obj:"2.5", diff:"medium", q:"Which centralized console connects an administrator's workstation to multiple VMware Type 1 hosts for remote management?", options:["vSphere","Server Core","rsyslog","Task Scheduler"], answer:0, explain:"<strong>vSphere</strong> is correct. vSphere is VMware's console that connects to multiple ESXi hosts for centralized remote management.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Server Core</b>: Server Core is a Windows install mode, not a VMware console.</span><span class='qd'><b>rsyslog</b>: rsyslog is a Linux logging service, not a management console.</span><span class='qd'><b>Task Scheduler</b>: Task Scheduler runs Windows jobs, not VMware management.</span>" },
  { id:"D2-075", domain:2, obj:"2.5", diff:"easy", q:"Which centralized console is used to manage Microsoft Hyper-V hosts and their VMs from an admin workstation?", options:["vSphere","Oracle VirtualBox","Hyper-V Manager console","VMware Workstation"], answer:2, explain:"<strong>Hyper-V Manager console</strong> is correct. The Hyper-V Manager console connects to one or more Hyper-V hosts for centralized VM administration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>vSphere</b>: vSphere manages VMware ESXi, not Hyper-V.</span><span class='qd'><b>Oracle VirtualBox</b>: Oracle VirtualBox is a Type 2 hypervisor, not a Hyper-V management console.</span><span class='qd'><b>VMware Workstation</b>: VMware Workstation is a Type 2 hypervisor, not a Hyper-V console.</span>" },
  { id:"D2-076", domain:2, obj:"2.3", diff:"medium", q:"A help-desk ticket is escalated to a sysadmin because the issue exceeds the technician's skill. In troubleshooting methodology, which action is this?", options:["Performing a root cause analysis","Escalating the issue to a more skilled administrator","Implementing preventive measures","Verifying full system functionality"], answer:1, explain:"<strong>Escalating the issue to a more skilled administrator</strong> is correct. When a problem exceeds the current technician's ability, the correct step is to escalate to a more skilled administrator or vendor.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Performing a root cause analysis</b>: Root cause analysis happens after resolution, not at escalation.</span><span class='qd'><b>Implementing preventive measures</b>: Preventive measures are applied after the fix is verified.</span><span class='qd'><b>Verifying full system functionality</b>: Verifying functionality occurs after a solution is implemented.</span>" },
  { id:"D2-077", domain:2, obj:"2.3", diff:"hard", q:"While following a plan of action, why should an administrator change only one thing at a time and then test?", options:["Because the OS forbids multiple simultaneous changes","To avoid needing any documentation","Because baselines prohibit testing","So it is clear exactly which change corrected the problem"], answer:3, explain:"<strong>So it is clear exactly which change corrected the problem</strong> is correct. Changing one item at a time and testing makes it clear which change fixed the issue, and lets you reverse ineffective changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because the OS forbids multiple simultaneous changes</b>: The OS does not technically forbid multiple changes; the reason is diagnostic clarity.</span><span class='qd'><b>To avoid needing any documentation</b>: This practice does not remove the need for documentation.</span><span class='qd'><b>Because baselines prohibit testing</b>: Baselines are references for comparison and do not prohibit testing.</span>" },
  { id:"D2-078", domain:2, obj:"2.4", diff:"medium", q:"Which clustering arrangement uses all member nodes to share the workload, giving the best hardware utilization but no idle standby?", options:["Active/passive","Cold standby","Active/active","Single-node deployment"], answer:2, explain:"<strong>Active/active</strong> is correct. Active/active uses every node to share the workload, maximizing hardware utilization with no idle standby node.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Active/passive</b>: Active/passive keeps a node idle as standby, reducing utilization.</span><span class='qd'><b>Cold standby</b>: Cold standby keeps a backup powered off, the least utilized.</span><span class='qd'><b>Single-node deployment</b>: A single-node deployment is not a cluster and has no failover.</span>" },
  { id:"D2-079", domain:2, obj:"2.2", diff:"easy", q:"Which type of address is hardcoded into a NIC by the manufacturer and used at layer 2?", options:["IP (logical) address","MAC (physical) address","Hostname","Default gateway"], answer:1, explain:"<strong>MAC (physical) address</strong> is correct. A MAC address is the physical, manufacturer-assigned layer 2 identifier burned into each NIC.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IP (logical) address</b>: An IP address is a logical layer 3 address assigned by an administrator.</span><span class='qd'><b>Hostname</b>: A hostname is a human-friendly name, not a hardcoded NIC identifier.</span><span class='qd'><b>Default gateway</b>: A default gateway is a router address, not a NIC's hardcoded identity.</span>" },
  { id:"D2-080", domain:2, obj:"2.5", diff:"hard", q:"An administrator equips a virtualization host with more NICs, RAM, and CPU than the VMs currently need to ensure capacity. What is this practice called?", options:["Overprovisioning the host","Underprovisioning the host","Slipstreaming the host","Bridging the host"], answer:0, explain:"<strong>Overprovisioning the host</strong> is correct. Overprovisioning equips the host with more resources than current demand requires to ensure capacity for the VMs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Underprovisioning the host</b>: Underprovisioning would leave too few resources, the opposite of this.</span><span class='qd'><b>Slipstreaming the host</b>: Slipstreaming integrates patches into install media, unrelated to capacity.</span><span class='qd'><b>Bridging the host</b>: Bridging is a virtual networking mode, not a provisioning strategy.</span>" },
  { id:"D2-081", domain:2, obj:"2.6", diff:"medium", q:"A PowerShell script written for Windows is run on a Linux server with only bash installed. What happens?", options:["It runs identically because all shells are compatible","bash automatically converts PowerShell cmdlets","It will not be understood because the required shell is not present","Linux runs it after a P2V migration"], answer:2, explain:"<strong>It will not be understood because the required shell is not present</strong> is correct. Scripts are shell-specific; a PowerShell script will not run without PowerShell, since bash does not understand cmdlets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It runs identically because all shells are compatible</b>: Shells are not universally compatible; scripts are language-specific.</span><span class='qd'><b>bash automatically converts PowerShell cmdlets</b>: bash does not convert PowerShell cmdlets automatically.</span><span class='qd'><b>Linux runs it after a P2V migration</b>: P2V migration converts physical servers to VMs and does not translate scripts.</span>" },
  { id:"D2-082", domain:2, obj:"2.5", diff:"easy", q:"Which three are examples of Type 1 hypervisors?", options:["VMware Workstation, VirtualBox, and Hyper-V","VirtualBox, ESXi, and Workstation","VMware ESXi, Microsoft Hyper-V, and KVM","Workstation, KVM, and VirtualBox"], answer:2, explain:"<strong>VMware ESXi, Microsoft Hyper-V, and KVM</strong> is correct. VMware ESXi, Microsoft Hyper-V, and KVM are Type 1 bare-metal hypervisors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>VMware Workstation, VirtualBox, and Hyper-V</b>: VMware Workstation and VirtualBox are Type 2, not Type 1.</span><span class='qd'><b>VirtualBox, ESXi, and Workstation</b>: VirtualBox and Workstation are Type 2 hypervisors.</span><span class='qd'><b>Workstation, KVM, and VirtualBox</b>: Workstation and VirtualBox are Type 2 hypervisors.</span>" },
  { id:"D2-083", domain:2, obj:"2.3", diff:"easy", q:"Which troubleshooting step comes first when a problem is reported?", options:["Implement preventive measures","Identify the problem","Verify full system functionality","Perform a root cause analysis"], answer:1, explain:"<strong>Identify the problem</strong> is correct. Identifying the problem is the first step of the troubleshooting methodology.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Implement preventive measures</b>: Preventive measures come near the end, after the fix.</span><span class='qd'><b>Verify full system functionality</b>: Verifying functionality follows implementing a solution.</span><span class='qd'><b>Perform a root cause analysis</b>: Root cause analysis happens after the problem is resolved.</span>" },
  { id:"D2-084", domain:2, obj:"2.4", diff:"easy", q:"Which describes a cold standby server in a failover design?", options:["A backup server actively sharing the load","A server that auto-fails over within milliseconds","A backup server that is powered off until needed","A server running all production VMs at once"], answer:2, explain:"<strong>A backup server that is powered off until needed</strong> is correct. A cold standby is a backup server kept powered off until it is needed to take over.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A backup server actively sharing the load</b>: Actively sharing the load describes active/active, not cold standby.</span><span class='qd'><b>A server that auto-fails over within milliseconds</b>: Millisecond automatic failover describes a hot/active-passive design, not cold standby.</span><span class='qd'><b>A server running all production VMs at once</b>: Running all production VMs is the active node's job, not a cold standby.</span>" },
  { id:"D2-085", domain:2, obj:"2.6", diff:"easy", q:"In a bash script, which construct runs one block if a condition is true and another if it is false?", options:["for loop","an array","if/else","a comparator"], answer:2, explain:"<strong>if/else</strong> is correct. The if/else conditional runs one block when the test is true and the else block when it is false.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>for loop</b>: A for loop repeats a fixed number of times, it does not branch on a condition.</span><span class='qd'><b>an array</b>: An array stores values; it does not branch.</span><span class='qd'><b>a comparator</b>: A comparator compares values but does not by itself branch code.</span>" },
  { id:"D2-086", domain:2, obj:"2.5", diff:"medium", q:"Which NIST cloud characteristic means consumers can provision resources themselves without contacting the provider?", options:["Measured service","On-demand self-service","Resource pooling","Broad network access"], answer:1, explain:"<strong>On-demand self-service</strong> is correct. On-demand self-service lets consumers provision resources themselves without provider intervention.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Measured service</b>: Measured service refers to metered billing.</span><span class='qd'><b>Resource pooling</b>: Resource pooling refers to shared, multi-tenant resources.</span><span class='qd'><b>Broad network access</b>: Broad network access refers to reaching services across device types.</span>" },
  { id:"D2-087", domain:2, obj:"2.3", diff:"medium", q:"After fixing a failed drive, an administrator adds RAID and scheduled backups so the same failure cannot recur. Which troubleshooting step is this?", options:["Implement preventive measures","Identify the problem","Establish a theory of probable cause","Determine the scope"], answer:0, explain:"<strong>Implement preventive measures</strong> is correct. Adding RAID and backups to stop a recurrence is implementing preventive measures.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Identify the problem</b>: Identifying the problem is the first step, already done.</span><span class='qd'><b>Establish a theory of probable cause</b>: Establishing a theory occurs before the fix, not after.</span><span class='qd'><b>Determine the scope</b>: Determining scope happens during identification, not prevention.</span>" },
  { id:"D2-088", domain:2, obj:"2.6", diff:"hard", q:"An administrator places a named, reusable block of account-creation commands at the top of a script and calls it multiple times. What is this called?", options:["A loop","A function","A comparator","An environment variable"], answer:1, explain:"<strong>A function</strong> is correct. A function is a named, reusable block of code that can be called multiple times within a script.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A loop</b>: A loop repeats code but is not a named callable block.</span><span class='qd'><b>A comparator</b>: A comparator compares values, not a reusable code block.</span><span class='qd'><b>An environment variable</b>: An environment variable stores a value, not a block of commands.</span>" },
  { id:"D2-089", domain:2, obj:"2.4", diff:"hard", q:"An administrator must ensure a database service stays online during a single node failure while keeping one node idle until needed. Which design fits?", options:["Active/active cluster","Active/passive failover cluster","Standalone server with daily backups","Round-robin DNS only"], answer:1, explain:"<strong>Active/passive failover cluster</strong> is correct. Active/passive keeps one node idle, ready to take over the database if the active node fails, ensuring continuity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Active/active cluster</b>: Active/active runs both nodes simultaneously rather than keeping one idle.</span><span class='qd'><b>Standalone server with daily backups</b>: A standalone server with backups does not provide automatic failover.</span><span class='qd'><b>Round-robin DNS only</b>: Round-robin DNS distributes lookups but does not provide stateful database failover.</span>" },
  { id:"D2-090", domain:2, obj:"2.7", diff:"easy", q:"Which document or record helps a sysadmin track warranties, license counts, and hardware location over the server lifecycle?", options:["A DHCP scope","An asset management inventory","A bash login script","A hosts file"], answer:1, explain:"<strong>An asset management inventory</strong> is correct. An asset management inventory tracks hardware, warranties, licenses, and locations across the lifecycle.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A DHCP scope</b>: A DHCP scope assigns IP addresses, not asset records.</span><span class='qd'><b>A bash login script</b>: A login script customizes user environments, not asset tracking.</span><span class='qd'><b>A hosts file</b>: A hosts file maps names to IPs, not assets.</span>" },
  { id:"D2-091", domain:2, obj:"2.6", diff:"medium", q:"A script that runs when a user signs in to map network drives and launch an application is an example of what?", options:["A login script","A shutdown script","A bootstrap web framework","A service script"], answer:0, explain:"<strong>A login script</strong> is correct. A login script runs at user sign-in to customize the environment, map drives, and launch applications.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A shutdown script</b>: A shutdown script runs when the computer powers down, not at login.</span><span class='qd'><b>A bootstrap web framework</b>: Bootstrap is a web page framework, not a user login script.</span><span class='qd'><b>A service script</b>: A service script manages services, not the user login environment.</span>" },
  { id:"D2-092", domain:2, obj:"2.4", diff:"medium", q:"Why is high availability essential in a basic virtualization deployment?", options:["The host system is a single point of failure that impacts every guest VM","Each VM has its own dedicated physical server","VMs cannot be replicated between hosts","Virtualization removes all hardware dependencies"], answer:0, explain:"<strong>The host system is a single point of failure that impacts every guest VM</strong> is correct. A single host is a single point of failure affecting all its guests, so HA (such as replication to another host) is essential.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Each VM has its own dedicated physical server</b>: VMs share one host; they do not each have a dedicated server.</span><span class='qd'><b>VMs cannot be replicated between hosts</b>: VMs can be replicated between hosts, which is part of HA.</span><span class='qd'><b>Virtualization removes all hardware dependencies</b>: Virtualization still depends on physical host hardware.</span>" },
  { id:"D2-093", domain:2, obj:"2.3", diff:"hard", q:"A single workstation cannot reach the file server, but all other workstations can. Where does the problem most likely lie?", options:["With the file server","With that one workstation","With the entire network backbone","With every workstation's DNS"], answer:1, explain:"<strong>With that one workstation</strong> is correct. If only one workstation is affected while others succeed, the issue is isolated to that workstation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>With the file server</b>: If the server were at fault, all workstations would fail, not just one.</span><span class='qd'><b>With the entire network backbone</b>: A backbone failure would affect many devices, not a single workstation.</span><span class='qd'><b>With every workstation's DNS</b>: If all DNS were broken, many clients would fail, not just one.</span>" },
  { id:"D2-094", domain:2, obj:"2.7", diff:"medium", q:"A sysadmin needs to forecast whether storage and CPU will meet demand over the next year based on monitoring trends. This is an example of what?", options:["Root cause analysis","Asset disposal","Capacity planning","Failover testing"], answer:2, explain:"<strong>Capacity planning</strong> is correct. Capacity planning uses monitoring trends to forecast whether resources will meet future demand.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Root cause analysis</b>: Root cause analysis investigates past failures, not future forecasting.</span><span class='qd'><b>Asset disposal</b>: Asset disposal is the end-of-life recycling phase, not forecasting.</span><span class='qd'><b>Failover testing</b>: Failover testing validates redundancy, not capacity forecasting.</span>" },
  { id:"D2-095", domain:2, obj:"2.3", diff:"medium", q:"An administrator restores service, then compares current metrics to the deployment baseline to confirm normal operation. Which step is this?", options:["Establish a plan of action","Identify the problem","Verify full system functionality","Document only at the end"], answer:2, explain:"<strong>Verify full system functionality</strong> is correct. Comparing current metrics to the baseline to confirm normal operation is verifying full system functionality.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Establish a plan of action</b>: Establishing a plan of action precedes implementing the fix.</span><span class='qd'><b>Identify the problem</b>: Identifying the problem is the first step, not post-fix verification.</span><span class='qd'><b>Document only at the end</b>: Documentation occurs throughout, not only at the end.</span>" },
  { id:"D2-096", domain:2, obj:"2.7", diff:"easy", q:"Which describes the four phases of the server lifecycle a sysadmin manages?", options:["Discover, Offer, Request, Acknowledge","Procurement, usage, end of life, and disposal/recycling","Identify, theorize, test, document","PV, VG, LV, and format"], answer:1, explain:"<strong>Procurement, usage, end of life, and disposal/recycling</strong> is correct. The server lifecycle phases are procurement, usage, end of life, and disposal/recycling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Discover, Offer, Request, Acknowledge</b>: DORA is the DHCP lease process, not the server lifecycle.</span><span class='qd'><b>Identify, theorize, test, document</b>: Those are troubleshooting steps, not lifecycle phases.</span><span class='qd'><b>PV, VG, LV, and format</b>: PV/VG/LV are LVM layers, not lifecycle phases.</span>" },
  { id:"D2-097", domain:2, obj:"2.7", diff:"medium", q:"An administrator must keep accurate records as branch offices open and close and IP usage changes. Which tool category helps track subnets and consumed addresses?", options:["IP address management (IPAM) software","A Type 2 hypervisor","A load balancer","A VM template"], answer:0, explain:"<strong>IP address management (IPAM) software</strong> is correct. IP address management (IPAM) software tracks subnets, consumed addresses, and available addresses as the environment changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A Type 2 hypervisor</b>: A Type 2 hypervisor runs VMs, it does not track IP inventory.</span><span class='qd'><b>A load balancer</b>: A load balancer distributes traffic, not address tracking.</span><span class='qd'><b>A VM template</b>: A VM template provisions VMs, not IP inventory.</span>" },
  { id:"D2-098", domain:2, obj:"2.7", diff:"easy", q:"Which licensing model assigns one license to each enabled processor core on a CPU, with extra unlicensed cores disabled?", options:["Per-seat licensing","Per-concurrent-user licensing","Site-based licensing","Per-core licensing"], answer:3, explain:"<strong>Per-core licensing</strong> is correct. Per-core licensing allocates a license to each enabled CPU core, and any cores beyond the licensed count are disabled.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Per-seat licensing</b>: Per-seat licensing assigns a license to each potential user, not to CPU cores.</span><span class='qd'><b>Per-concurrent-user licensing</b>: Per-concurrent-user licensing limits simultaneous users, not CPU cores.</span><span class='qd'><b>Site-based licensing</b>: Site-based licensing covers a whole site or building, not individual cores.</span>" },
  { id:"D2-099", domain:2, obj:"2.7", diff:"medium", q:"A company exceeds its purchased license count during an audit and must purchase additional licenses to become compliant. This correction is known as what?", options:["Slipstreaming","Overprovisioning","Failing over","Truing up"], answer:3, explain:"<strong>Truing up</strong> is correct. When an organization exceeds its licenses, it must true up by purchasing the additional licenses needed for compliance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Slipstreaming</b>: Slipstreaming integrates patches into install media, not license correction.</span><span class='qd'><b>Overprovisioning</b>: Overprovisioning adds spare hardware capacity, not licenses.</span><span class='qd'><b>Failing over</b>: Failing over shifts workloads to a standby node, unrelated to licensing.</span>" },
  { id:"D2-100", domain:2, obj:"2.7", diff:"easy", q:"Which licensing model uses client access licenses (CALs) to determine how many simultaneous client connections a server permits?", options:["Node-locked licensing","Per-server licensing","Per-socket licensing","Subscription licensing"], answer:1, explain:"<strong>Per-server licensing</strong> is correct. Per-server licensing uses CALs to set the number of simultaneous client connections a server allows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Node-locked licensing</b>: Node-locked licensing ties software to one node or dongle, not CAL connections.</span><span class='qd'><b>Per-socket licensing</b>: Per-socket licensing allocates licenses to CPU sockets, not client connections.</span><span class='qd'><b>Subscription licensing</b>: Subscription licensing is a billing model, not a CAL connection limit.</span>" }
);
